import requests

class ApiClient:
    def __init__(self, base_url: str):
        self.base_url = base_url
        self.session = requests.Session()

    def _request(self, method: str, endpoint: str, **kwargs):
        url = f"{self.base_url}{endpoint}"
        try:
            response = self.session.request(method, url, **kwargs)
            response.raise_for_status()  # HTTP hataları için istisna fırlat
            return response
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"API isteği başarısız oldu: {e}") from e

    def login(self, username, password) -> dict:
        """
        API'ye kullanıcı adı ve şifre ile giriş yapar.
        Giriş başarılı olursa, oturum çerezleri veya token'lar 'requests.Session' objesi içinde saklanır.
        """
        login_data = {"username": username, "password": password}
        response = self._request("POST", "/api/login", json=login_data)
        return response.json()

    def get_protected_data(self) -> dict:
        """
        Giriş yapılmış bir oturum gerektiren korumalı verileri çeker.
        Oturum bilgileri otomatik olarak 'requests.Session' tarafından gönderilir.
        """
        response = self._request("GET", "/api/data")
        return response.json()

    def logout(self) -> dict:
        """
        Mevcut oturumdan çıkış yapar.
        """
        response = self._request("POST", "/api/logout")
        return response.json()

    def close(self):
        """
        Oturumu kapatır ve kaynakları serbest bırakır.
        """
        self.session.close()
